// ========== MNIST 真实数据集 (28x28) ==========
// 从 MNIST testing 目录提取
// 训练集: 800 张 | 测试集: 200 张

export interface MNISTSample {
  input: number[]  // 784维 (28x28), 值 0-1
  label: number   // 0-9
}

export const MNIST_STATS = {
  trainSize: 800,
  testSize: 200,
  imageSize: 28,
  inputDim: 784,
  numClasses: 10
}

function parseBase64(base64: string): number[] {
  const binary = atob(base64)
  const result: number[] = new Array(784)
  for (let i = 0; i < 784; i++) {
    result[i] = binary.charCodeAt(i) / 255
  }
  return result
}

